import React from "react";
import { ArrowUpRight, ArrowDownLeft, Sun, Moon } from "lucide-react";
import { useCurrency } from "../context/CurrencyContext";


export default function HomeScreen({ 
  balance, 
  savingsBalance, 
  transactions = [], 
  userName, 
  openScreen, 
  darkMode, 
  toggleDarkMode 
}) {
  return (
    <div className={`px-6 pb-24 min-h-screen animate-fade-in ${darkMode ? "bg-gray-900 text-gray-100" : "bg-gray-50 text-gray-900"}`}>

      {/* Greeting and dark mode toggle */}
      <div className="flex justify-between items-center mb-6 pt-6">
        <h1 className="text-2xl font-bold">Hello, {userName} 👋</h1>
        <button onClick={toggleDarkMode}>
          {darkMode ? <Sun size={22} /> : <Moon size={22} />}
        </button>
      </div>

      {/* Total Balance Card */}
      <div className={`rounded-3xl p-6 mb-8 shadow-lg ${darkMode ? "bg-gray-800" : "bg-gradient-to-br from-emerald-600 to-teal-800 text-white"}`}>
        <div className="flex justify-between items-start mb-2">
          <span className={`${darkMode ? "text-gray-400" : "text-emerald-100"} text-sm font-medium`}>Total Balance</span>
          <span className="text-lg font-bold">Nest.</span>
        </div>
        <div className="text-4xl font-bold mb-4 tracking-tight">{formatAmount(balance)}
</div>

        {/* Savings Balance */}
        <p className={`${darkMode ? "text-gray-300" : "text-emerald-200"} font-medium mb-4`}>
          Savings: ${formatCurrency(savingsBalance)}
        </p>

        {/* Buttons */}
        <div className="flex gap-3">
          <button
            onClick={() => openScreen("Deposit")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition-colors ${darkMode ? "bg-emerald-600/30 hover:bg-emerald-600/40 text-white" : "bg-emerald-500/20 hover:bg-emerald-500/30"}`}
          >
            <ArrowUpRight className="w-4 h-4" /> Deposit
          </button>

          <button
            onClick={() => openScreen("Withdraw")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition-colors ${darkMode ? "bg-emerald-600/30 hover:bg-emerald-600/40 text-white" : "bg-emerald-500/20 hover:bg-emerald-500/30"}`}
          >
            <ArrowDownLeft className="w-4 h-4" /> Withdraw
          </button>
        </div>

        {/* Savings actions */}
        <div className="flex gap-3 mt-3">
          <button
            onClick={() => openScreen("SavingsDeposit")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition-colors ${darkMode ? "bg-emerald-600/30 hover:bg-emerald-600/40 text-white" : "bg-emerald-500/20 hover:bg-emerald-500/30"}`}
          >
            Save
          </button>

          <button
            onClick={() => openScreen("SavingsWithdraw")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition-colors ${darkMode ? "bg-emerald-600/30 hover:bg-emerald-600/40 text-white" : "bg-emerald-500/20 hover:bg-emerald-500/30"}`}
          >
            Withdraw Savings
          </button>
        </div>
      </div>

      {/* Recent Transactions */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h2 className="font-bold text-lg">Recent Transactions</h2>
          <button
            onClick={() => openScreen("Transactions")}
            className={`${darkMode ? "text-gray-400" : "text-gray-400"}`}
          >
            ▶
          </button>
        </div>

        <div className="space-y-4">
          {transactions.slice(0, 5).map((t) => {
            const isDeposit = t.type.includes("deposit");
            return (
              <div
                key={t.id}
                className={`flex items-center justify-between p-3 rounded-xl border cursor-pointer transition ${darkMode ? "bg-gray-800 border-gray-700 hover:bg-gray-700" : "bg-white border-gray-50 hover:bg-gray-50"}`}
                onClick={() => openScreen("TransactionReceipt", t)}
              >
                <div className="flex items-center gap-3">
                  <div
                    className={`w-10 h-10 rounded-full flex items-center justify-center ${isDeposit ? "bg-emerald-100 text-emerald-600" : "bg-red-100 text-red-600"}`}
                  >
                    {isDeposit ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
                  </div>
                  <div>
                    <p className={`font-semibold ${darkMode ? "text-gray-100" : "text-gray-800"}`}>{t.title}</p>
                    <p className="text-xs text-gray-400">{t.date}</p>
                  </div>
                </div>
                <span className={`font-bold text-sm ${isDeposit ? "text-emerald-600" : "text-gray-800"}`}>
                  {isDeposit ? "+" : "-"}${formatCurrency(t.amount)}
                </span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
